{
  "family": "patch_test_pass",
  "case_id": "validate_record_missing_fields",
  "bug_category": "parsing_validation",
  "difficulty": "easy",
  "user": "In the Rust crate at {project_root}, fix the parsing validation bug in src/lib.rs so the tests pass. Keep the behavior compact and aligned with the existing tests.",
  "expected_tool_sequence": ["read_file", "apply_patch", "cargo_test"],
  "expected_output": null,
  "files": {
    "Cargo.toml": "[package]
name = "validate_record_missing_fields"
version = "0.1.0"
edition = "2021"

[dependencies]
",
    "src/lib.rs": "pub fn validate_record(line: &str) -> bool {
    let mut seen_id = false;
    let mut seen_name = false;

    for part in line.split(';') {
        let Some((key, value)) = part.split_once('=') else {
            return false;
        };

        if value.is_empty() {
            return false;
        }

        match key {
            "id" => {
                if !value.chars().all(|c| c.is_ascii_digit()) {
                    return false;
                }
                seen_id = true;
            }
            "name" => seen_name = true,
            "active" => {
                if value != "true" && value != "false" {
                    return false;
                }
            }
            _ => return false,
        }
    }

    seen_id || seen_name
}

#[cfg(test)]
mod tests {
    use super::validate_record;

    #[test]
    fn accepts_complete_valid_record() {
        assert!(validate_record("id=42;name=alice;active=true"));
    }

    #[test]
    fn rejects_missing_name() {
        assert!(!validate_record("id=42;active=true"));
    }

    #[test]
    fn rejects_missing_id() {
        assert!(!validate_record("name=alice;active=false"));
    }

    #[test]
    fn rejects_bad_active_value() {
        assert!(!validate_record("id=42;name=alice;active=yes"));
    }

    #[test]
    fn rejects_unknown_field() {
        assert!(!validate_record("id=42;name=alice;role=admin"));
    }
}
"
  },
  "steps": [
    {
      "tool": "read_file",
      "file_path": "src/lib.rs"
    },
    {
      "tool": "apply_patch",
      "file_path": "src/lib.rs",
      "find": "    seen_id || seen_name
",
      "replace": "    seen_id && seen_name
"
    },
    {
      "tool": "cargo_test",
      "expect_status": "success"
    }
  ],
  "final": "FINAL: Updated the record validation so both required fields must be present, and the test suite now passes."
}

