{
  "family": "patch_test_pass",
  "case_id": "team_expense_report_missing_zero_groups",
  "bug_category": "aggregation_reporting",
  "difficulty": "medium",
  "user": "In the Rust crate at {project_root}, fix the reporting logic in src/lib.rs so the tests pass. The report should include every requested team, even if it has no matching paid expenses, and totals should only include paid items. Keep the output ordering by requested team list.",
  "expected_tool_sequence": ["read_file", "apply_patch", "cargo_test"],
  "expected_output": null,
  "files": {
    "Cargo.toml": "[package]
name = "team_expense_report"
version = "0.1.0"
edition = "2021"

[lib]
path = "src/lib.rs"
",
    "src/lib.rs": "use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Expense {
    pub team: &'static str,
    pub amount: u32,
    pub paid: bool,
}

pub fn expense_report(expenses: &[Expense], teams: &[&str]) -> String {
    let mut totals: BTreeMap<&str, u32> = BTreeMap::new();

    for expense in expenses {
        if expense.paid && teams.contains(&expense.team) {
            *totals.entry(expense.team).or_insert(0) += expense.amount;
        }
    }

    teams
        .iter()
        .filter_map(|team| totals.get(team).map(|total| format!("{}:{}", team, total)))
        .collect::<Vec<_>>()
        .join("\n")
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn includes_zero_total_for_requested_team_without_paid_items() {
        let expenses = [
            Expense { team: "ops", amount: 30, paid: false },
            Expense { team: "eng", amount: 70, paid: true },
            Expense { team: "sales", amount: 25, paid: true },
        ];

        let report = expense_report(&expenses, &["ops", "eng", "hr"]);
        assert_eq!(report, "ops:0\neng:70\nhr:0");
    }

    #[test]
    fn preserves_requested_order_and_ignores_unrequested_teams() {
        let expenses = [
            Expense { team: "sales", amount: 10, paid: true },
            Expense { team: "eng", amount: 20, paid: true },
            Expense { team: "sales", amount: 5, paid: true },
            Expense { team: "ops", amount: 99, paid: true },
        ];

        let report = expense_report(&expenses, &["sales", "eng"]);
        assert_eq!(report, "sales:15\neng:20");
    }
}
"
  },
  "steps": [
    {
      "tool": "read_file",
      "file_path": "src/lib.rs"
    },
    {
      "tool": "apply_patch",
      "file_path": "src/lib.rs",
      "find": "    teams
        .iter()
        .filter_map(|team| totals.get(team).map(|total| format!("{}:{}", team, total)))
        .collect::<Vec<_>>()
        .join("\n")
",
      "replace": "    teams
        .iter()
        .map(|team| format!("{}:{}", team, totals.get(team).copied().unwrap_or(0)))
        .collect::<Vec<_>>()
        .join("\n")
"
    },
    {
      "tool": "cargo_test",
      "expect_status": "success"
    }
  ],
  "final": "FINAL: Updated the report generation to include every requested team in the original requested order, defaulting missing paid totals to 0 while still ignoring unrequested teams."
