  "family": "patch_test_pass",
  "case_id": "ticket_queue_state_transitions_rules",
  "bug_category": "state_transitions",
  "difficulty": "hard",
  "user": "In the Rust crate at {project_root}, fix the state transition logic in src/lib.rs so the tests pass. Preserve the compact design and update only the bugged behavior.",
  "expected_tool_sequence": [
    "read_file",
    "apply_patch",
    "cargo_test"
  ],
  "expected_output": null,
  "files": {
    "Cargo.toml": "[package]
name = "ticket_queue_state_transitions_rules"
version = "0.1.0"
edition = "2021"

[lib]
path = "src/lib.rs"
",
    "src/lib.rs": "#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    New,
    Active,
    Waiting,
    Closed,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Ticket {
    pub status: Status,
    pub assignee: Option<String>,
    pub resolution: Option<String>,
    pub waiting_cycles: u32,
    pub history: Vec<Status>,
}

impl Ticket {
    pub fn new() -> Self {
        Self {
            status: Status::New,
            assignee: None,
            resolution: None,
            waiting_cycles: 0,
            history: vec![Status::New],
        }
    }
}

pub enum Event {
    Assign(String),
    StartWork,
    Blocked,
    Unblocked,
    Resolve(String),
    Reopen,
}

pub fn apply_event(ticket: &mut Ticket, event: Event) {
    match event {
        Event::Assign(name) => {
            ticket.assignee = Some(name);
        }
        Event::StartWork => {
            if ticket.status != Status::Closed {
                ticket.status = Status::Active;
                ticket.history.push(Status::Active);
            }
        }
        Event::Blocked => {
            if ticket.status == Status::Active {
                ticket.status = Status::Waiting;
                ticket.waiting_cycles += 1;
                ticket.history.push(Status::Waiting);
            }
        }
        Event::Unblocked => {
            if ticket.status == Status::Waiting {
                ticket.status = Status::New;
                ticket.history.push(Status::New);
            }
        }
        Event::Resolve(note) => {
            if ticket.assignee.is_some() {
                ticket.status = Status::Closed;
                ticket.resolution = Some(note);
                ticket.history.push(Status::Closed);
            }
        }
        Event::Reopen => {
            if ticket.status == Status::Closed {
                ticket.status = Status::New;
                ticket.history.push(Status::New);
            }
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn start_work_requires_assignee_and_clears_resolution_when_reopened() {
        let mut t = Ticket::new();
        apply_event(&mut t, Event::StartWork);
        assert_eq!(t.status, Status::New);
        assert_eq!(t.history, vec![Status::New]);

        apply_event(&mut t, Event::Assign("dev".into()));
        apply_event(&mut t, Event::StartWork);
        assert_eq!(t.status, Status::Active);

        apply_event(&mut t, Event::Resolve("done".into()));
        assert_eq!(t.status, Status::Closed);
        assert_eq!(t.resolution.as_deref(), Some("done"));

        apply_event(&mut t, Event::Reopen);
        assert_eq!(t.status, Status::Active);
        assert_eq!(t.resolution, None);
    }

    #[test]
    fn unblock_returns_to_active_without_incrementing_waiting_cycles() {
        let mut t = Ticket::new();
        apply_event(&mut t, Event::Assign("ops".into()));
        apply_event(&mut t, Event::StartWork);
        apply_event(&mut t, Event::Blocked);
        assert_eq!(t.status, Status::Waiting);
        assert_eq!(t.waiting_cycles, 1);

        apply_event(&mut t, Event::Unblocked);
        assert_eq!(t.status, Status::Active);
        assert_eq!(t.waiting_cycles, 1);
        assert_eq!(
            t.history,
            vec![Status::New, Status::Active, Status::Waiting, Status::Active]
        );
    }

    #[test]
    fn resolve_requires_active_state_and_assignee() {
        let mut t = Ticket::new();
        apply_event(&mut t, Event::Assign("qa".into()));
        apply_event(&mut t, Event::Resolve("premature".into()));
        assert_eq!(t.status, Status::New);
        assert_eq!(t.resolution, None);

        apply_event(&mut t, Event::StartWork);
        apply_event(&mut t, Event::Blocked);
        apply_event(&mut t, Event::Resolve("still blocked".into()));
        assert_eq!(t.status, Status::Waiting);
        assert_eq!(t.resolution, None);

        apply_event(&mut t, Event::Unblocked);
        apply_event(&mut t, Event::Resolve("fixed".into()));
        assert_eq!(t.status, Status::Closed);
        assert_eq!(t.resolution.as_deref(), Some("fixed"));
    }
}
"
  },
  "steps": [
    {
      "tool": "read_file",
      "file_path": "src/lib.rs"
    },
    {
      "tool": "apply_patch",
      "file_path": "src/lib.rs",
      "find": "        Event::StartWork => {
            if ticket.status != Status::Closed {
                ticket.status = Status::Active;
                ticket.history.push(Status::Active);
            }
        }
        Event::Blocked => {
            if ticket.status == Status::Active {
                ticket.status = Status::Waiting;
                ticket.waiting_cycles += 1;
                ticket.history.push(Status::Waiting);
            }
        }
        Event::Unblocked => {
            if ticket.status == Status::Waiting {
                ticket.status = Status::New;
                ticket.history.push(Status::New);
            }
        }
        Event::Resolve(note) => {
            if ticket.assignee.is_some() {
                ticket.status = Status::Closed;
                ticket.resolution = Some(note);
                ticket.history.push(Status::Closed);
            }
        }
        Event::Reopen => {
            if ticket.status == Status::Closed {
                ticket.status = Status::New;
                ticket.history.push(Status::New);
            }
        }
",
      "replace": "        Event::StartWork => {
            if ticket.assignee.is_some() && matches!(ticket.status, Status::New | Status::Waiting) {
                ticket.status = Status::Active;
                ticket.history.push(Status::Active);
            }
        }
        Event::Blocked => {
            if ticket.status == Status::Active {
                ticket.status = Status::Waiting;
                ticket.waiting_cycles += 1;
                ticket.history.push(Status::Waiting);
            }
        }
        Event::Unblocked => {
            if ticket.status == Status::Waiting {
                ticket.status = Status::Active;
                ticket.history.push(Status::Active);
            }
        }
        Event::Resolve(note) => {
            if ticket.assignee.is_some() && ticket.status == Status::Active {
                ticket.status = Status::Closed;
                ticket.resolution = Some(note);
                ticket.history.push(Status::Closed);
            }
        }
        Event::Reopen => {
            if ticket.status == Status::Closed {
                ticket.status = Status::Active;
                ticket.resolution = None;
                ticket.history.push(Status::Active);
            }
        }
"
    },
    {
      "tool": "cargo_test",
      "expect_status": "success"
    }
  ],
  "final": "FINAL: Patched src/lib.rs so ticket transitions now enforce assignee/active-state rules, unblock back to Active, and reopen clears resolution while returning to Active; cargo test passes."
}

