    defaults.merge(file).merge(env)
}
",
      "replace": "pub fn effective_config(defaults: Config, file: Config, env: Config) -> Config {
    env.merge(file).merge(defaults)
}
"
    },
    {
      "tool": "cargo_test",
      "expect_status": "success"
    }
  ],
  "final": "FINAL: Fixed config layer precedence so env overrides file, file overrides defaults, and lower-precedence layers only fill missing values."
}

