    "src/main.rs": "use std::collections::HashSet;

fn main() {
    let input = "1|Alice|42|true\n2|Bob|x|false\n1|Cara|55|true\n3|Dan|77|maybe\n4|Eve|90\n5||12|true\n6|Frank|100|false";

