            invalid.push(format!("line {}: bad score", line_no));
            continue;
        }

        if active != "true" && active != "false" {
            invalid.push(format!("line {}: bad active", line_no));
            continue;
        }

        valid += 1;
    }

    let mut out = format!("valid:{} invalid:{}", valid, invalid.len());
    for msg in invalid {
        out.push('\n');
        out.push_str(&msg);
    }
